composeOverride:
# Generated by McHarbor App Store
services:
  {{serviceName}}:
    image: {{image}}
    container_name: {{containerName}}
    restart: unless-stopped
    depends_on:
      - {{serviceName}}-db
{{ports}}
    volumes:
      - {{env.GHOST_CONTENT_PATH}}:/var/lib/ghost/content
    environment:
      url: {{env.GHOST_URL}}
      database__client: mysql
      database__connection__host: {{serviceName}}-db
      database__connection__user: {{env.GHOST_DB_USER}}
      database__connection__password: {{env.GHOST_DB_PASSWORD}}
      database__connection__database: {{env.GHOST_DB_NAME}}
  {{serviceName}}-db:
    image: mysql:8
    container_name: {{containerName}}-db
    restart: unless-stopped
    volumes:
      - {{env.GHOST_DB_PATH}}:/var/lib/mysql
    environment:
      MYSQL_DATABASE: {{env.GHOST_DB_NAME}}
      MYSQL_USER: {{env.GHOST_DB_USER}}
      MYSQL_PASSWORD: {{env.GHOST_DB_PASSWORD}}
      MYSQL_ROOT_PASSWORD: {{env.GHOST_DB_ROOT_PASSWORD}}
